import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;
import java.util.Scanner;

public class SecurePathTraversal {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter the file name: ");
        String fileName = scanner.nextLine();

        Path filePath = Paths.get("/path/to/directory/", fileName).normalize();

        if (filePath.startsWith(Paths.get("/path/to/directory/")) && Files.exists(filePath)) {
            System.out.println("File exists!");
        } else {
            System.out.println("File does not exist or access is denied!");
        }
    }
}

